module traffic_light
(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output reg red
);
parameter idle = 2'b00;
parameter s1_red = 2'b01;
parameter s2_yellow = 2'b10;
parameter s3_green = 2'b11;
reg [7:0] cnt;
reg [1:0] state;
reg p_red, p_yellow, p_green;
always @(*) begin
    case (state)
        idle: begin
            p_red = 0;
            p_yellow = 0;
            p_green = 0;
            state = s1_red;
        end
        s1_red: begin
            p_red = 1;
            if (cnt == 3) begin
                state = s3_green;
                p_red = 0;
            end
        end
        s2_yellow: begin
            p_yellow = 1;
            if (cnt == 3) begin
                state = s1_red;
                p_yellow = 0;
            end
        end
        s3_green: begin
            p_green = 1;
            if (cnt == 3) begin
                state = s2_yellow;
                p_green = 0;
            end
        end
    endcase
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) cnt <= 8'd10;
    else begin
        if (pass_request && green) cnt <= 8'd10;
        else begin
            if (!green && p_green) cnt <= 8'd60;
            else begin
                if (!yellow && p_yellow) cnt <= 8'd5;
                else begin
                    if (!red && p_red) cnt <= 8'd10;
                end
            end
        end
    end
end
assign clock = cnt;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        red <= 0;
        yellow <= 0;
        green <= 0;
    end
    else begin
        if (!red && p_red) red <= 1;
        else begin
            if (!yellow && p_yellow) yellow <= 1;
            else begin
                if (!green && p_green) green <= 1;
            end
        end
    end
end
endmodule
